const raw = String($json.callback_data || '').trim();
const out = {
  ...$json,
  route: 'unknown',
  lesson_id: '',
  question_text: ''
};
let match;
if ((match = raw.match(/^lesson:next:(.+)$/))) {
  out.route = 'next';
  out.lesson_id = match[1];
} else if ((match = raw.match(/^lesson:save:(.+)$/))) {
  out.route = 'save';
  out.lesson_id = match[1];
} else if ((match = raw.match(/^lesson:ai:(.+)$/))) {
  out.route = 'ai_open';
  out.lesson_id = match[1];
} else if ((match = raw.match(/^ai:suggest:(.+):(life|spot|practice)$/))) {
  out.route = 'ai_suggest';
  out.lesson_id = match[1];
  out.question_text = match[2] === 'life'
    ? 'Как это искажение проявляется в обычной жизни?'
    : match[2] === 'spot'
      ? 'Как замечать это искажение у себя в моменте?'
      : 'Что делать на практике, чтобы не попадать в эту ловушку?';
}
return [{ json: out }];

const source = $node['Normalize Callback Route']?.json || {};
return [{
