const message = $json.message || {};
const text = String(message.text || message.caption || '').trim();
const entities = message.entities || [];
const isCommand = entities.some((entity) => entity.type === 'bot_command');
const startMatch = text.match(/^\/start(?:\s+(.+))?$/);
const route = message.voice ? 'voice' : (isCommand ? 'command' : (text ? 'text' : 'ignore'));
return [{
  json: {
    ...$json,
    tg_id: String(message.chat?.id || ''),
    chat_id: String(message.chat?.id || ''),
    first_name: message.from?.first_name || '',
    last_name: message.from?.last_name || '',
    tg_username: message.from?.username || '',
    message_text: text,
    route,
    start_payload: startMatch?.[1] || '',
    is_start: Boolean(startMatch)
  }
}];

