const esc = (value) => String(value ?? '').replace(/[&<>]/g, (m) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;' }[m]));
const lesson = $json;
const parts = [`<b>${esc(lesson.title || 'Урок')}</b>`];
