    lesson_text: parts.join('\n\n')
  }
}];

function safe(name) {
  try {
    return $node[name].json || null;
  } catch (error) {
    return null;
  }
}
const lesson = safe('Resolve AI Lesson') || {};
const thread = safe('Ensure AI Thread') || {};
const callbackInput = safe('Prepare AI Suggest Input');
const textInput = safe('Prepare AI Text Input');
const voiceInput = safe('Prepare AI Voice Input');
const source = callbackInput?.question_text ? callbackInput : (voiceInput?.question_text ? voiceInput : textInput || {});
const history = $items('Get AI History', 0).map((item) => item.json).filter((item) => item.message_text).reverse().map((item) => ({ role: item.role, content: item.message_text }));
const questionText = String(source.question_text || lesson.question_text || '').trim();
const firstName = source.first_name || lesson.first_name || 'друг';
const related = Array.isArray(lesson.related_slugs) ? lesson.related_slugs.join(', ') : String(lesson.related_slugs || '');
const systemPrompt = [
  'Ты — практичный помощник курса по когнитивным искажениям.',
  `Обращайся к пользователю по имени: ${firstName}.`,
  `Текущий урок: ${lesson.title || ''}`,
  lesson.short_text || '',
  lesson.ai_context || '',
  related ? `Связанные искажения: ${related}` : '',
  'Отвечай по-русски, коротко, ясно и прикладно.',
  'Опирайся на контекст урока, не выдумывай лишние факты.',
  'Если полезно, дай 2-4 конкретных шага или вопроса для самопроверки.',
  'Для Telegram используй только HTML-теги <b>, без markdown.'
].filter(Boolean).join('\n\n');
return [{
  json: {
    chat_id: lesson.chat_id || thread.chat_id || source.chat_id,
    lesson_id: lesson.id || thread.lesson_id || source.lesson_id,
    message_type: source.message_type || 'text',
    openrouter_endpoint: lesson.openrouter_endpoint || source.openrouter_endpoint || 'https://openrouter.ai/api/v1/chat/completions',
    openrouter_api_key: lesson.openrouter_api_key || source.openrouter_api_key || '',
    provider: 'openrouter',
    question_text: questionText,
    request_body: {
      model: lesson.openrouter_model || source.openrouter_model || 'qwen/qwen3-coder:free',
      messages: [
        { role: 'system', content: systemPrompt },
        ...history,
        { role: 'user', content: questionText || 'Помоги понять текущее искажение.' }
      ]
    },
    site_url: lesson.site_url || source.site_url || 'https://cognitive-biaces.vercel.app',
    tg_id: lesson.tg_id || thread.tg_id || source.tg_id,
    thread_id: thread.thread_id,
    system_prompt: systemPrompt
  }
}];

const source = $node['Build AI Prompt']?.json || {};
const answer = $json.text || $json.output || $json.response?.choices?.[0]?.message?.content || $json.answer_text || 'AI не вернул текстовый ответ.';
return [{
  json: {
    ...source,
    answer_text: String(answer).trim(),
    model: $json.model || source.request_body?.model || 'unknown',
    input_tokens: $json.response?.usage?.prompt_tokens || null,
    output_tokens: $json.response?.usage?.completion_tokens || null,
    status: $json.status || 'ok'
  }
}];

const source = $node['Parse AI Response']?.json || {};
let text = source.answer_text ?? source.text ?? '';
if (typeof text !== 'string') text = String(text);
text = text.replace(/^###\s*(.+)$/gm, '<b>$1</b>');
text = text.replace(/\*\*(.+?)\*\*/gs, '<b>$1</b>');
text = text.replace(/__(.+?)__/gs, '<b>$1</b>');
text = text.replace(/\*(.+?)\*/gs, '$1');
text = text.replace(/_(.+?)_/gs, '$1');
text = text.replace(/```+/g, '').replace(/`+/g, '');
text = text.replace(/\\n/g, '\n');
text = text.replace(/<script[\s\S]*?<\/script>/gi, '');
text = text.replace(/\son\w+="[^"]*"/gi, '');
text = text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
for (const tag of ['b','i','u','s','code','pre','a','tg-spoiler']) {
  const open = new RegExp(`&lt;${tag}(\\s+[^&]*?)?&gt;`, 'gi');
  const close = new RegExp(`&lt;\\/${tag}\\s*&gt;`, 'gi');
  text = text.replace(open, (_m, attrs='') => `<${tag}${attrs}>`).replace(close, `</${tag}>`);
}
return [{ json: { ...source, answer_text: text } }];

return [{
  json: {
    ...$json,
    chat_id: $json.chat_id,
    lesson_id: $json.lesson_id,
    message: $json.answer_text,
    session_key: `${$json.chat_id || $json.tg_id || ''}_lesson_${$json.lesson_id || ''}`
  }
}];

const MAX_LEN = 3500;
const input = items?.[0]?.json || {};
const raw = input.message || input.answer_text || '';
const chat_id = input.chat_id || input.tg_id || null;
const lesson_id = input.lesson_id || null;
const text = typeof raw === 'string' ? raw : String(raw);
if (!text) return [];
const tokens = text.match(/<\/?[a-zA-Z][^>]*>|[^<]+/g) || [];
const chunks = [];
let buffer = '';
for (const token of tokens) {
  if ((buffer + token).length > MAX_LEN && buffer) {
    chunks.push(buffer);
    buffer = token;
  } else {
    buffer += token;
  }
}
if (buffer) chunks.push(buffer);
return chunks.map((message, index) => ({ json: { message, chat_id, lesson_id, is_last: index === chunks.length - 1 } }));
